import request from '@/utils/request'

export function getVoteContestantList(id) {
  return request({
    url: `/voteContestant/selectAllContestant?voteId=${id}&page=1&size=100`,
    method: 'get',
  })
}

export function getVoteContestantDetail(contestantId) {
  return request({
    url: `/voteContestant/getDetails?id=${contestantId}`,
    method: 'get',
  })
}

export function addContestant(data) {
  return request({
    url: `/voteContestant/add`,
    method: 'post',
    data: data,
  })
}

export function updateContestant(data) {
  return request({
    url: `/voteContestant/update`,
    method: 'post',
    data: data,
  })
}

export function deleteContestant(contestantId) {
  return request({
    url: `/voteContestant/delete?id=${contestantId}`,
    method: 'post',
  })
}
